Framescript.script:
var _this = this;
var konteiner_1_fon = new createjs.Container();
var konteiner_2_karty = new createjs.Container();
var konteiner_3_granitsy = new createjs.Container();
var konteiner_4_kontury = new createjs.Container();
var konteiner_5_goroda = new createjs.Container();
var konteiner_6_uslovnye_oboznacheniya = new createjs.Container();
this.stop();
function onAppStart() {
    getfind();   
	bbdddf();
	findactivelaier(_this.mov_menu.cmbox_epoha_SSSR, true);
	konteiner_1_fon.getChildByName("Ф_1").visible=true;
};
function bbdddf() {
	_this.text_nazvanie.text = 'Электронная карта России';
	_this.getChildByName('mov_oprogramme').visible=false;
	_this.text_nazvanie_poyasnenie.text='Панкратов С.К.';
	for (let i = 2; i < konteiner_1_fon.children.length; i++) {
		konteiner_1_fon.getChildAt(i).visible = false;
	};
	for (let i = 0; i < konteiner_2_karty.children.length; i++) {
		konteiner_2_karty.getChildAt(i).visible = false;
	};
	for (let i = 0; i < konteiner_3_granitsy.children.length; i++) {
		konteiner_3_granitsy.getChildAt(i).visible = false;
	};
	for (let i = 0; i < konteiner_4_kontury.children.length; i++) {
		konteiner_4_kontury.getChildAt(i).visible = false;
	};
	findactivelaier(_this.mov_menu.chbox_fiz_karta, false);
	findactivelaier(_this.mov_menu.chbox_K_G_RI_1914, false);
	findactivelaier(_this.mov_menu.chbox_K_G_SSSR_1939, false);
	findactivelaier(_this.mov_menu.chbox_K_G_SSSR_1941, false);	
	findactivelaier(_this.mov_menu.chbox_K_G_SSSR_1945_1991, false);
	findactivelaier(_this.mov_menu.chbox_K_G_RF_2009, false);
};
function getaccoun() {
	if (papercode(_this.mov_menu.chbox_adm_delenie)) {
		konteiner_1_fon.getChildByName("Ф_РИ").visible=false;
	} else {
		konteiner_1_fon.getChildByName("Ф_РИ").visible=true;
	}
}
function digitallayer() {
	if (papercode(_this.mov_menu.chbox_adm_delenie)) {
		konteiner_1_fon.getChildByName("Ф_1").visible=false;
	} else {
		konteiner_1_fon.getChildByName("Ф_1").visible=true;
	}
}
function aledeleted() {
	if (papercode(_this.mov_menu.chbox_adm_delenie)) {
		konteiner_1_fon.getChildByName("Ф_2").visible=false;
	} else {
		konteiner_1_fon.getChildByName("Ф_2").visible=true;
	}
}
function bbbbb8(event) {
	bbdddf();
	currentcheckbox = event.currentTarget;
	galochka = event.currentTarget.name;
	localvarb = papercode(currentcheckbox);	
	_this.text_nazvanie_poyasnenie.text='';
	switch (galochka) {
		case 'cmbox_epoha_RI' :
			{
				_this.text_nazvanie.text='Российская Империя';
				getaccoun();
				break;
			};
		case 'cmbox_epoha_SSSR' :
			{
				_this.text_nazvanie.text='Союз Советских Социалистических Республик';
				digitallayer();
				break;
			};
		case 'cmbox_epoha_RF' :
			{
				_this.text_nazvanie.text='Российская Федерация';
				aledeleted();
				break;
		}
	}
};
function findlastlaer(event) {
	var galochka;
	var sloy;
	var sloy_uo;
	var nazvanie;
	var nazvanie_poyasnenie;
	var localvarb;
	var sloy_object;
	var localvara;
	currentcheckbox = event.currentTarget;
	galochka = event.currentTarget.name;
	localvarb = papercode(currentcheckbox);	
	localvarb = !localvarb;	
	sloy='';
	sloy_object=null;
	nazvanie_poyasnenie='';
	_this.text_nazvanie_poyasnenie.text='';
	localvara=konteiner_2_karty; 
	switch (galochka) {
		case 'chbox_K_G_RI_1914':
			{
				nazvanie = 'Граница Российской Империи в 1914г.';
				sloy_object = 'К_Г_РИ_1914';
				localvara = konteiner_3_granitsy;
				break;
			};
		case 'chbox_K_G_SSSR_1939' :
			{
				nazvanie='Граница СССР в 1939г.';
				sloy_object='К_Г_СССР_1939';
				localvara=konteiner_3_granitsy;
				break;
			};
		case 'chbox_K_G_SSSR_1941' :
			{
				nazvanie='Граница СССР накануне Великой Отечественной войны';
				sloy_object='К_Г_СССР_1941';
				localvara=konteiner_3_granitsy;
				break;
			};
		case 'chbox_K_G_SSSR_1945_1991' :
			{
				nazvanie='Граница Советского Союза после войны';
				sloy_object='К_Г_СССР_1945_1991';
				localvara=konteiner_3_granitsy;
				break;
			};
		case 'chbox_K_G_RF_2009' :
			{
				nazvanie='Современная граница России';
				sloy_object='К_Г_РФ_2009';
				localvara=konteiner_3_granitsy;
				break;
			};
		case 'chbox_fiz_karta' :
			{
				nazvanie='Физическая карта России';
				sloy_object='Ф_ФИЗ';
				localvara=konteiner_1_fon;
				break;
			};
		case 'chbox_K_ZD_RI' :
			{
				nazvanie='Железные дороги Российской Империи';
				sloy_object='К_ЖД_РИ';
				localvara=konteiner_4_kontury;
				break;
			};
		case 'chbox_K_ZD_SSSR' :
			{
				nazvanie='Железные дороги СССР';
				sloy_object='К_ЖД_СССР';
				localvara=konteiner_4_kontury;
				break;
			};
		case 'chbox_K_RZD' :
			{
				nazvanie='Российские железные дороги: прошлое и будущее';
				sloy_object='К_РЖД';
				localvara=konteiner_4_kontury;
				break;
			};		
		case 'chbox_N_RI_E1' :
			{
				nazvanie='Расширение границ России до начала XX века';
				nazvanie_poyasnenie='(учебный атлас 1910г.)';
				sloy_object='Н_РИ_Э1';
				break;
			};
		case 'chbox_N_RI_GG' :
			{
				nazvanie='Генерал - губернаторства';
				sloy_object='Н_РИ_ГГ';
				break;
			};
		case 'chbox_N_RI_KP_2' :
			{
				nazvanie='Отмена крепостного права. Размер зем. наделов.';
				sloy_object='Н_РИ_КП_2';
				break;
			};
		case 'chbox_N_SSSR_1941' :
			{
				nazvanie='Изменения границ перед войной (1939-1940 гг)';
				sloy_object='Н_СССР_1941';
				break;
			};
		case 'chbox_N_SSSR_OKK' :
			{
				nazvanie='Оккупированные территории и границы СССР в 1941-1945 гг';
				sloy_object='Н_СССР_ОКК';
				break;
			};
		case 'chbox_N_SSSR_PR1941' :
			{
				nazvanie='План раздела СССР в 1941 г. (III Рейх)';
				sloy_object='Н_СССР_ПР1941';
				break;
			};
		case 'chbox_N_SSSR_1945' :
			{
				nazvanie='Изменения границ после войны   (1945 г.)';
				sloy_object='Н_СССР_1945';
				break;
			};
		case 'chbox_N_SSSR_ER' :
			{
				nazvanie='Экономические районы СССР';
				sloy_object='Н_СССР_ЭР';
				break;
			};		
		case 'chbox_N_RF_FO' :
			{
				nazvanie='Федеральные округа РФ';
				sloy_object='Н_РФ_ФО';
				break;
			};
		case 'chbox_N_RF_OR' :
			{
				nazvanie='Проект объединения регионов';
				sloy_object='Н_РФ_ОР';
				break;
			};
		case 'chbox_N_U_G' :
			{
				nazvanie='Изменения границ Украины в XX веке';
				sloy_object='Н_У_Г';
				break;
			};
		case 'chbox_N_U_MN' :
			{
				nazvanie='Малороссия-Новороссия';
				sloy_object='Н_У_МН';
				break;
			};
		case 'chbox_N_U_P' :
			{
				nazvanie='Политический раскол регионов на Украине';
				sloy_object='Н_У_П';
				break;
			};
		case 'chbox_N_NR' :
			{
				nazvanie='Непризнанные республики и территориальные претензии';
				sloy_object='Н_НР';
				break;
			};
		case 'chbox_adm_delenie' :
			{
				nazvanie='Административное деление';
				sloy_object='Ф_АД_РФ';
				localvara=konteiner_1_fon;
				break;
			};
			};
	sloy=sloy_object;
	if (galochka) {
		_this.text_nazvanie.text=nazvanie;
	} else {
		text_nazvanie.text='';
	}
	localvara.getChildByName(sloy).visible = localvarb;
	if (localvarb) {
		localvara.addChild(_this.sloy_object);
	};
};
function bbddff(event) {
	findactivelaier(_this.mov_menu.chbox_ochischenie, false);
	findactivelaier(_this.mov_menu.cmbox_epoha_RI, false);
	findactivelaier(_this.mov_menu.cmbox_epoha_SSSR, false);
	findactivelaier(_this.mov_menu.cmbox_epoha_RF, false);
	findactivelaier(_this.mov_menu.chbox_K_G_RI_1914, false);
	findactivelaier(_this.mov_menu.chbox_K_G_SSSR_1939, false);
	findactivelaier(_this.mov_menu.chbox_K_G_SSSR_1941, false);
	findactivelaier(_this.mov_menu.chbox_K_G_SSSR_1945_1991, false);
	findactivelaier(_this.mov_menu.chbox_K_G_RF_2009, false);
	findactivelaier(_this.mov_menu.chbox_adm_delenie, false);
	findactivelaier(_this.mov_menu.chbox_fiz_karta, false);
	findactivelaier(_this.mov_nalozheniya.chbox_K_ZD_RI, false);
	findactivelaier(_this.mov_nalozheniya.chbox_K_ZD_SSSR, false);
	findactivelaier(_this.mov_nalozheniya.chbox_K_RZD, false);
	findactivelaier(_this.mov_nalozheniya.chbox_N_RI_E1, false);
	findactivelaier(_this.mov_nalozheniya.chbox_N_RI_GG, false);
	findactivelaier(_this.mov_nalozheniya.chbox_N_SSSR_1941, false);
	findactivelaier(_this.mov_nalozheniya.chbox_N_SSSR_OKK, false);
	findactivelaier(_this.mov_nalozheniya.chbox_N_SSSR_1945, false);
	findactivelaier(_this.mov_nalozheniya.chbox_N_SSSR_ER, false);
	findactivelaier(_this.mov_nalozheniya.chbox_N_RF_FO, false);
	findactivelaier(_this.mov_nalozheniya.chbox_N_U_G, false);
	findactivelaier(_this.mov_nalozheniya.chbox_N_NR, false);
	bbdddf();
	bbbbb8(event)
};
function getfind() {
	konteiner_1_fon.addChild(_this.Ф0_МОРЕ);
	konteiner_1_fon.addChild(_this.Ф0_СУША);
	konteiner_1_fon.addChild(_this.Ф_РИ);
	konteiner_1_fon.addChild(_this.Ф_1);
	konteiner_1_fon.addChild(_this.Ф_2);
	konteiner_1_fon.addChild(_this.Ф_ФИЗ);	
	konteiner_1_fon.addChild(_this.Ф_АД_РИ);
	konteiner_1_fon.addChild(_this.Ф_АД_СССР);
	konteiner_1_fon.addChild(_this.Ф_АД_РФ);
	konteiner_3_granitsy.addChild(_this.К_Г_РИ_1914);
	konteiner_3_granitsy.addChild(_this.К_Г_СССР_1939);
	konteiner_3_granitsy.addChild(_this.К_Г_СССР_1941);
	konteiner_3_granitsy.addChild(_this.К_Г_СССР_1945_1991);
	konteiner_3_granitsy.addChild(_this.К_Г_РФ_2009);
	konteiner_4_kontury.addChild(_this.К_ЖД_РИ);
	konteiner_4_kontury.addChild(_this.К_ЖД_СССР);
	konteiner_4_kontury.addChild(_this.К_ЖД_РФ);
	konteiner_4_kontury.addChild(_this.К_РЖД);
	konteiner_2_karty.addChild(_this.Н_РИ_Э1);
	konteiner_2_karty.addChild(_this.Н_РИ_ГГ);
	konteiner_2_karty.addChild(_this.Н_РИ_КП_1);
	konteiner_2_karty.addChild(_this.Н_РИ_КП_2);
	konteiner_2_karty.addChild(_this.Н_СССР_1941);
	konteiner_2_karty.addChild(_this.Н_СССР_ОКК);
	konteiner_2_karty.addChild(_this.Н_СССР_1945);
	konteiner_2_karty.addChild(_this.Н_СССР_ЭР);
	konteiner_2_karty.addChild(_this.Н_РФ_ФО);
	konteiner_2_karty.addChild(_this.Н_У_Г);
	konteiner_2_karty.addChild(_this.Н_НР);
	_this.addChild(konteiner_1_fon);
	_this.addChild(konteiner_2_karty);
	_this.addChild(konteiner_3_granitsy);
	_this.addChild(konteiner_4_kontury);
	_this.addChild(_this.mov_nalozheniya);
	_this.addChild(_this.mov_menu);
	_this.addChild(_this.mov_knopka_karty_nalozheniya);
	_this.addChild(_this.mov_knopka_oprogramme);
	_this.addChild(_this.mov_oprogramme);	
};
function undeletedcount() {
if (_this.getChildByName('mov_nalozheniya').visible) {
		_this.getChildByName('mov_nalozheniya').visible=false;
		_this.getChildByName('mov_menu').visible=false;
		_this.getChildByName('mov_cccccc18').visible=false;
	}
	else {
		_this.getChildByName('mov_nalozheniya').visible=true;
		_this.getChildByName('mov_menu').visible=true;
		_this.getChildByName('mov_cccccc18').visible=true;
	}
}
function cccccc18() {
if (_this.getChildByName('mov_oprogramme').visible) {
		_this.getChildByName('mov_oprogramme').visible=false;			
	}
	else {
		_this.getChildByName('mov_oprogramme').visible=true;			
	}
}
function findactivelaier(chboxname, selected) {
	let currentcheckbox;
	currentcheckbox = chboxname;
	if (selected == true) {
		currentcheckbox.gotoAndStop(1); 
	} else if (selected == false) {
		currentcheckbox.gotoAndStop(0); 
	};
};
function papercode(chboxname) { 
	currentcheckboxframe = chboxname.currentFrame;
	if (currentcheckboxframe == 1) {
		return true;
	} else if (currentcheckboxframe == 0) {
		return false;
	};
};
onAppStart();
_this.mov_menu.chbox_adm_delenie.on('click', findlastlaer); 
